def _map_component(regions):
    d_json = json.dumps(regions, ensure_ascii=False, separators=(",", ":"))
    border_json = json.dumps(_BORDER)
    return (_MAP_HEAD.replace("__VIEWBOX__", _VIEWBOX)
            + "const D=" + d_json + ";\nconst BORDER=" + border_json + ";"
            + _MAP_SCRIPT)


